const req = $('Receive Documents Request').first().json;
return [{
  json: {
    client_id: req.query.client_id,
    timestamp: req.headers['x-caiac-timestamp'],
    signature: req.headers['x-caiac-signature'],
    token: (req.headers.authorization || '').replace(/^Bearer\s+/i, ''),
    webhook_secret: req.headers['x-webhook-secret'] || ''
  }
}];

const session = $input.first().json;
const requestedSlug = $('Receive Documents Request').first().json.query.client_id;
const allowedRoles = ['staff', 'admin', 'owner'];
const hasClientAccess = allowedRoles.includes(session.role) && session.slug === requestedSlug;
const isCaiacStaff = session.is_caiac_staff === true;
if (!hasClientAccess && !isCaiacStaff) {
  throw new Error('Insufficient permissions');
}
return [{
  json: {
    user_id: session.user_id,
    role: session.role,
    client_id: session.client_id,
    client_slug: requestedSlug,
    is_caiac_staff: isCaiacStaff,
    name: session.name,
    email: session.email
  }
}];

const docs = $input.all()
  .map(item => item.json)
  .filter(doc => doc.filename);
return [{ json: { documents: docs, count: docs.length } }];
